function loadStorage(key, fallback) {
  try { const v = localStorage.getItem(key); return v ? JSON.parse(v) : fallback; }
  catch { return fallback; }
}
function saveStorage(key, val) {
  try { localStorage.setItem(key, JSON.stringify(val)); } catch {}
}

// ─── HELPERS ──────────────────────────────────────────────────────────────────
function grdNumero(n) { return `GRD-${String(n).padStart(5, "0")}`; }
function now() { return new Date().toISOString(); }
function fmtDate(iso) {
  if (!iso) return "—";
  const d = new Date(iso);
  return d.toLocaleDateString("pt-BR") + " " + d.toLocaleTimeString("pt-BR", { hour: "2-digit", minute: "2-digit" });
}

// Calcula o hash SHA-256 (impressão digital de integridade) de um PDF em base64.
// Usa a Web Crypto API nativa do navegador — sem dependência externa.
async function calcularHash(base64) {
  try {
    if (!base64 || !window.crypto?.subtle) return null;
    const bin = atob(base64.includes(",") ? base64.split(",")[1] : base64);
    const bytes = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
    const buf = await window.crypto.subtle.digest("SHA-256", bytes);
    return Array.from(new Uint8Array(buf)).map(b => b.toString(16).padStart(2, "0")).join("");
  } catch { return null; }
}
function hashCurto(h) { return h ? `${h.slice(0, 8)}…${h.slice(-8)}`.toUpperCase() : "—"; }
function badge(status) {
  const s = statusCor[status] || statusCor.pendente;
  const label = { pendente: "Pendente", aceito: "Aceito", enviado: "Enviado", recusado: "Recusado" }[status] || "Pendente";
  return (
    <span style={{ background: s.bg, color: s.c, border: `1px solid ${s.c}33`, borderRadius: 99, padding: "2px 10px", fontSize: 11, fontWeight: 700, letterSpacing: 0.5 }}>
      {label}
    </span>
  );
}

// Barra de progresso de aceites de um GRD (ex.: "2 de 3 aceitos")
function ProgressoAceite({ tokens, compacto }) {
  const total = tokens?.length || 0;
  const aceitos = tokens?.filter(t => t.status === "aceito").length || 0;
  const recusados = tokens?.filter(t => t.status === "recusado").length || 0;
  const pct = total ? Math.round((aceitos / total) * 100) : 0;
  const cor = recusados > 0 ? "#EF4444" : aceitos === total && total > 0 ? "#22C55E" : "#FBBF24";
  return (
    <div style={{ minWidth: compacto ? 90 : 130 }}>
      <div style={{ display: "flex", justifyContent: "space-between", fontSize: 10.5, color: T.textMut, marginBottom: 3 }}>
        <span>{aceitos} de {total} aceito(s)</span>
        {!compacto && <span style={{ color: cor, fontWeight: 700 }}>{pct}%</span>}
      </div>
      <div style={{ height: 6, borderRadius: 99, overflow: "hidden", background: T.bgPanel, display: "flex" }}>
        <div style={{ width: `${pct}%`, background: cor, transition: "width 0.3s" }} />
      </div>
    </div>
  );
}

