// ─── STAMP (carimbo visual com FUNDO TRANSPARENTE) ────────────────────────────
// Renderiza um selo retangular estilo carimbo de tinta, sem preenchimento sólido.
// Em produção, este mesmo desenho é gravado no PDF via pdf-lib (transparente).
function CarimboSVG({ grd, colab, data, cor = "#1E3A5F", escala = 1 }) {
  const W = 300, H = 110;
  return (
    <svg width={W * escala} height={H * escala} viewBox={`0 0 ${W} ${H}`} xmlns="http://www.w3.org/2000/svg" style={{ display: "block" }}>
      {/* fundo transparente: nenhum <rect> preenchido cobrindo tudo */}
      <rect x="3" y="3" width={W - 6} height={H - 6} rx="8" fill="none" stroke={cor} strokeWidth="2.5" />
      <rect x="8" y="8" width={W - 16} height={H - 16} rx="5" fill="none" stroke={cor} strokeWidth="0.8" opacity="0.6" />
      <text x={W / 2} y="28" textAnchor="middle" fontFamily="Arial, sans-serif" fontSize="13" fontWeight="bold" fill={cor} letterSpacing="0.5">C3 ENGENHARIA &amp; SOLUÇÕES</text>
      <line x1="20" y1="36" x2={W - 20} y2="36" stroke={cor} strokeWidth="0.8" opacity="0.5" />
      <text x={W / 2} y="58" textAnchor="middle" fontFamily="Arial, sans-serif" fontSize="20" fontWeight="bold" fill={cor} letterSpacing="1">{grd}</text>
      <text x="20" y="78" fontFamily="Arial, sans-serif" fontSize="10" fill={cor}>Emissor: <tspan fontWeight="bold">{colab.nome}</tspan></text>
      <text x="20" y="92" fontFamily="Arial, sans-serif" fontSize="10" fill={cor}>Matrícula: <tspan fontWeight="bold">{colab.matricula}</tspan></text>
      <text x={W - 20} y="100" textAnchor="end" fontFamily="Arial, sans-serif" fontSize="8" fill={cor} opacity="0.8">{fmtDate(data)}</text>
    </svg>
  );
}

// ─── PDF-LIB: carimbo transparente + rodapé de controle ───────────────────────
// Carrega pdf-lib e fontkit sob demanda do CDN (funciona no navegador).
let _pdfLibPromise = null;
let _fontkitPromise = null;
let _fontBytesPromise = null;
function carregarPdfLib() {
  if (!_pdfLibPromise) _pdfLibPromise = import("https://esm.sh/pdf-lib@1.17.1");
  return _pdfLibPromise;
}
function carregarFontkit() {
  if (!_fontkitPromise) _fontkitPromise = import("https://esm.sh/@pdf-lib/fontkit@1.1.1");
  return _fontkitPromise;
}
// Fonte com suporte a acentuação (DejaVu Sans). Baixada uma única vez.
function carregarFontBytes() {
  if (!_fontBytesPromise) {
    _fontBytesPromise = fetch("https://cdn.jsdelivr.net/npm/dejavu-fonts-ttf@2.37.3/ttf/DejaVuSans.ttf")
      .then(r => r.arrayBuffer());
  }
  return _fontBytesPromise;
}
function carregarFontBytesBold() {
  return fetch("https://cdn.jsdelivr.net/npm/dejavu-fonts-ttf@2.37.3/ttf/DejaVuSans-Bold.ttf").then(r => r.arrayBuffer());
}

function base64ToUint8(base64) {
  const bin = atob(base64.includes(",") ? base64.split(",")[1] : base64);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  return bytes;
}

function baixarBytes(bytes, nome) {
  const blob = new Blob([bytes], { type: "application/pdf" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url; a.download = nome; a.click();
  URL.revokeObjectURL(url);
}

// Carrega o PDF com fontes acentuadas (DejaVu). Se o CDN da fonte/fontkit
// estiver indisponível, cai para Helvetica padrão (sem download externo).
async function abrirPdfComFontes(base64) {
  const { PDFDocument, rgb, StandardFonts } = await carregarPdfLib();
  const pdf = await PDFDocument.load(base64ToUint8(base64));
  try {
    const fontkitMod = await carregarFontkit();
    pdf.registerFontkit(fontkitMod.default || fontkitMod);
    const [fb, fbb] = await Promise.all([carregarFontBytes(), carregarFontBytesBold()]);
    const font = await pdf.embedFont(fb);
    const fontB = await pdf.embedFont(fbb);
    return { PDFDocument, rgb, pdf, font, fontB, acentos: true };
  } catch (e) {
    // fallback: fontes padrão do PDF (sem necessidade de internet)
    const font = await pdf.embedFont(StandardFonts.Helvetica);
    const fontB = await pdf.embedFont(StandardFonts.HelveticaBold);
    return { PDFDocument, rgb, pdf, font, fontB, acentos: false };
  }
}

// Remove acentos como salvaguarda quando estiver no modo fallback (Helvetica)
function semAcento(txt) {
  return txt.normalize("NFD").replace(/[\u0300-\u036f]/g, "");
}

// Desenha o carimbo (borda + textos) no canto superior direito da 1ª página.
// Fundo transparente: nenhum retângulo preenchido — só linhas e texto.
async function carimbarPDF(base64, grd, colab, dataIso) {
  const { rgb, pdf, font, fontB, acentos } = await abrirPdfComFontes(base64);
  const cor = rgb(0.118, 0.227, 0.373); // #1E3A5F
  const txt = s => acentos ? s : semAcento(s);

  const pagina = pdf.getPages()[0];
  const { width, height } = pagina.getSize();
  // Carimbo menor, ancorado no canto INFERIOR ESQUERDO
  const W = 175, H = 60;
  const x = 22;   // margem da esquerda
  const y = 22;   // margem de baixo

  pagina.drawRectangle({ x, y, width: W, height: H, borderColor: cor, borderWidth: 1.3 });
  pagina.drawText(txt("C3 ENGENHARIA & SOLUÇÕES"), { x: x + 9, y: y + H - 14, size: 6.5, font: fontB, color: cor });
  pagina.drawLine({ start: { x: x + 9, y: y + H - 19 }, end: { x: x + W - 9, y: y + H - 19 }, thickness: 0.4, color: cor });
  pagina.drawText(grd, { x: x + 9, y: y + H - 36, size: 12, font: fontB, color: cor });
  pagina.drawText(txt(`Emissor: ${colab.nome}`), { x: x + 9, y: y + 15, size: 5.8, font, color: cor });
  pagina.drawText(txt(`Matrícula: ${colab.matricula}`), { x: x + 9, y: y + 8, size: 5.8, font, color: cor });
  pagina.drawText(fmtDate(dataIso), { x: x + W - 62, y: y + 3, size: 5, font, color: cor });

  return await pdf.save();
}

// Aplica rodapé de controle em TODAS as páginas (cópia do destinatário).
async function aplicarRodapePDF(base64, textoRodape) {
  const { rgb, pdf, font, acentos } = await abrirPdfComFontes(base64);
  const cor = rgb(0.4, 0.4, 0.4);
  const texto = acentos ? textoRodape : semAcento(textoRodape);
  pdf.getPages().forEach(p => {
    const { width } = p.getSize();
    const size = 7;
    const largura = font.widthOfTextAtSize(texto, size);
    p.drawText(texto, { x: Math.max(12, (width - largura) / 2), y: 14, size, font, color: cor });
  });
  return await pdf.save();
}

// ─── TELA DE LOGIN ────────────────────────────────────────────────────────────
function LoginScreen({ users, onLogin }) {
  const [email, setEmail] = useState("");
  const [senha, setSenha] = useState("");
  const [erro, setErro] = useState("");
  const [loading, setLoading] = useState(false);

  function handleLogin() {
    setLoading(true);
    setTimeout(() => {
      const u = users.find(x => x.email === email && x.senha === senha);
      if (u) { setErro(""); onLogin(u); }
      else { setErro("E-mail ou senha incorretos."); }
      setLoading(false);
    }, 600);
  }

  return (
    <div style={{ minHeight: "100vh", background: T.bg, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "'Segoe UI', sans-serif" }}>
      <div style={{ width: 400, background: T.card, border: `1px solid ${T.cardBorder}`, borderRadius: 16, padding: 40 }}>
        {/* Logo */}
        <div style={{ textAlign: "center", marginBottom: 32 }}>
          <img src={LOGO} alt="C3 Engenharia & Soluções" style={{ height: 72, objectFit: "contain", marginBottom: 16 }} />
          <div style={{ color: T.textMut, fontSize: 13 }}>Gestão de Registro de Documentos</div>
        </div>

        <div style={{ marginBottom: 16 }}>
          <label style={{ color: "rgba(255,255,255,0.6)", fontSize: 12, fontWeight: 600, display: "block", marginBottom: 6 }}>E-MAIL</label>
          <input value={email} onChange={e => setEmail(e.target.value)} onKeyDown={e => e.key === "Enter" && handleLogin()} placeholder="seu@email.com.br" style={{ width: "100%", padding: "10px 14px", borderRadius: 8, border: "1px solid rgba(255,255,255,0.15)", background: "rgba(255,255,255,0.07)", color: "#fff", fontSize: 14, outline: "none", boxSizing: "border-box" }} />
        </div>
        <div style={{ marginBottom: 24 }}>
          <label style={{ color: "rgba(255,255,255,0.6)", fontSize: 12, fontWeight: 600, display: "block", marginBottom: 6 }}>SENHA</label>
          <input type="password" value={senha} onChange={e => setSenha(e.target.value)} onKeyDown={e => e.key === "Enter" && handleLogin()} placeholder="••••••••" style={{ width: "100%", padding: "10px 14px", borderRadius: 8, border: "1px solid rgba(255,255,255,0.15)", background: "rgba(255,255,255,0.07)", color: "#fff", fontSize: 14, outline: "none", boxSizing: "border-box" }} />
        </div>
        {erro && <div style={{ background: "rgba(239,68,68,0.15)", border: "1px solid rgba(239,68,68,0.3)", borderRadius: 8, padding: "10px 14px", color: "#FCA5A5", fontSize: 13, marginBottom: 16 }}>{erro}</div>}
        <button onClick={handleLogin} disabled={loading} style={{ width: "100%", padding: "12px", borderRadius: 8, background: loading ? "#334155" : "linear-gradient(90deg, #2563EB, #1D4ED8)", color: "#fff", fontWeight: 700, fontSize: 15, border: "none", cursor: loading ? "not-allowed" : "pointer", transition: "opacity 0.2s" }}>
          {loading ? "Entrando..." : "Entrar"}
        </button>
      </div>
    </div>
  );
}

